const cfg = $('Set Config').first().json;
const row = $json;
function extractId(u){ if(!u) return ''; u=String(u).trim(); const m=u.match(/[-\w]{25,}/); return m?m[0]:u; }
const get = (keys) => { for(const k of keys){ if(row[k]!==undefined && row[k]!==null && String(row[k]).trim()!==''){ return String(row[k]).trim(); } } return ''; };
return { json: {
  blogNo: get(['Blog.No.','Blog.No','Blog No','BlogNo']),
  blogTitle: get(['Blog-Article','Blog Article','Blog-article']),
  categoryName: get(['Category (name)','Category(name)','Category( name)','Category name','Category']),
  categoryLink: get(['Category( Link)','Category (Link)','Category(Link)','Category Link']),
  folderId: extractId(get(['Folder_url','Folder Url','Folder URL'])),
  shop: cfg.shop, apiVersion: cfg.apiVersion, blogId: cfg.blogId,
  blogHandle: cfg.blogHandle, publicDomain: cfg.publicDomain, websiteUrl: cfg.websiteUrl
} };

const files = $json.files || [];
const photos = files.filter(f => /\.(png|jpe?g|webp|gif)$/i.test(f.name || '')).map(f => ({ id: f.id, name: f.name, baseName: f.name.replace(/\.[^.]+$/, ''), driveUrl: 'https://drive.google.com/thumbnail?id=' + f.id + '&sz=w2000' }));
return [{ json: { photos } }];

const parse = $('Parse Row').first().json;
const docHtml = $('Export Doc').first().json.docHtml || '';
const categoryName = parse.categoryName || '';
const categoryLink = parse.categoryLink || '';
const websiteUrl = parse.websiteUrl || 'https://marblebee.com/';
const photos = $('Collect Photos').first().json.photos || [];
const resp = $json || {};
const nodes = (resp.data && resp.data.nodes) ? resp.data.nodes : [];
const imgByAlt = {};
for (const n of nodes) { if (n && n.alt && n.image && n.image.url) { imgByAlt[n.alt] = { url: n.image.url, w: n.image.width || null, h: n.image.height || null }; } }
const fallback = {};
for (const p of photos) { fallback[p.baseName] = p.driveUrl; }
function imgFor(b) { return imgByAlt[b] || (fallback[b] ? { url: fallback[b], w: null, h: null } : null); }
let html = docHtml;
const styleMatch = html.match(/<style[^>]*>([\s\S]*?)<\/style>/i);
let styleInner = styleMatch ? styleMatch[1] : '';
const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
let body = bodyMatch ? bodyMatch[1] : html;
body = body.replace(/^[\s\S]*?<\/(?:h1|h2)>/i, ''); const scope = '.mb-blog-content';
if (styleInner) { styleInner = styleInner.replace(/(^|})\s*([^{}@]+)\s*\{/g, function(m, br, sel) { const s = sel.split(',').map(x => x.trim()).filter(Boolean).map(x => scope + ' ' + x).join(', '); return br + ' ' + s + ' {'; }); }
styleInner += ' ' + scope + ' a { color: inherit !important; text-decoration: none !important; }'; styleInner += ' ' + scope + ' h1, ' + scope + ' h2, ' + scope + ' h3, ' + scope + ' h4 { text-align: left !important; }';
body = body.replace(/&#12304;/g, '\u3010').replace(/&#12305;/g, '\u3011').replace(/&#x3010;/gi, '\u3010').replace(/&#x3011;/gi, '\u3011');
function buildImgBlock(m, names) { const parts = names.split('/').map(s => s.trim()).filter(Boolean); const first = parts[0] || ''; const prefix = first.replace(/[^-]*$/, ''); const resolved = parts.map(p => (p.indexOf('-') >= 0 ? p : (prefix + p))); const two = resolved.length > 1; const validImgs = resolved.map(function(base){ const img = imgFor(base); return img ? { base: base, img: img } : null; }).filter(Boolean); if (!validImgs.length) return ''; const paired = validImgs.length > 1; function makeImg(img, base) { const u = img.url; const ws = [360,480,600,720,840,960,1280,1440]; const sep = u.indexOf('?') >= 0 ? '&' : '?'; const srcset = ws.map(function(w){ return u + sep + 'width=' + w + ' ' + w + 'w'; }).join(', '); const sizes = paired ? '(max-width:600px) 46vw, 46vw' : '(max-width:600px) 95vw, 820px'; return '<img src="' + u + '" alt="' + base + '" loading="lazy" srcset="' + srcset + '" sizes="' + sizes + '" />'; } return validImgs.map(function(x){ return makeImg(x.img, x.base); }).join(''); }
const phRe = /\u3010\s*insert\s*image\s*:\s*([^\u3011]+)\u3011/;
const phReG = /\u3010\s*insert\s*image\s*:\s*([^\u3011]+)\u3011/gi;
body = body.replace(/<p[^>]*>(?:(?!<\/p>)[\s\S])*?\u3010\s*insert\s*image\s*:\s*[^\u3011]+\u3011(?:(?!<\/p>)[\s\S])*?<\/p>/gi, function(block) { const mm = block.match(phRe); return mm ? buildImgBlock(mm[0], mm[1]) : block; });
body = body.replace(phReG, function(m, names) { return buildImgBlock(m, names); });
function escapeReg(s) { return s.replace(/[^a-zA-Z0-9 ]/g, function(c) { return '\\' + c; }); }
const segs = body.split(/(<[^>]+>)/);
const catRe = categoryName ? new RegExp(escapeReg(categoryName), 'gi') : null;
for (let i = 0; i < segs.length; i++) { if (segs[i].charAt(0) === '<') continue; let t = segs[i]; if (websiteUrl) { t = t.replace(/MarbleBee/gi, function(m){ return '<a href="' + websiteUrl + '" style="color:inherit;text-decoration:none;">' + m + '</a>'; }); } if (catRe && categoryLink) { t = t.replace(catRe, function(m){ return '<a href="' + categoryLink + '" style="color:inherit;text-decoration:none;">' + m + '</a>'; }); } segs[i] = t; }
body = segs.join('');
function styleDocTables(h){ return h.replace(/<table\b[^>]*>([\s\S]*?)<\/table>/gi, function(full, inner){ var ri = 0; var ni = inner.replace(/<tr\b[^>]*>([\s\S]*?)<\/tr>/gi, function(rf, cells){ var first = (ri === 0); var ci = 0; var nc = cells.replace(/<(?:td|th)\b([^>]*)>([\s\S]*?)<\/(?:td|th)>/gi, function(cf, attrs, content){ var bg = first ? 'background:#e5e5e5;' : (ci === 0 ? 'background:#f3f3f3;' : ''); ci++; var keep = ''; var csm = attrs.match(/\bcolspan\s*=\s*"?\d+"?/i); if (csm) keep += ' ' + csm[0]; var rsm = attrs.match(/\browspan\s*=\s*"?\d+"?/i); if (rsm) keep += ' ' + rsm[0]; content = content.replace(/<p\b[^>]*>/gi, '<p style="margin:0;padding:0;">'); return '<td' + keep + ' style="' + bg + 'border:1px solid #ccc;padding:12px;vertical-align:top;">' + content + '</td>'; }); ri++; return '<tr>' + nc + '</tr>'; }); return '<div style="overflow-x:auto;margin:20px 0;"><table style="width:100%;border-collapse:collapse;">' + ni + '</table></div>'; }); }
body = styleDocTables(body);
const finalHtml = (styleInner ? '<style>' + styleInner + '</style>' : '') + '<div class="mb-blog-content">' + body + '</div>';
return { json: { body_html: finalHtml, blogTitle: parse.blogTitle, categoryName: categoryName, blogNo: parse.blogNo } };

const photos = $('Collect Photos').first().json.photos || [];
function mime(name){ const e=(String(name).split('.').pop()||'').toLowerCase(); return e==='png'?'image/png':(e==='jpg'||e==='jpeg')?'image/jpeg':e==='webp'?'image/webp':e==='gif'?'image/gif':'application/octet-stream'; }
return photos.map(p => ({ json: { photoId: p.id, baseName: p.baseName, fileName: p.name, mimeType: mime(p.name) } }));

const items = $input.all();
const results = [];
for (let i = 0; i < items.length; i++) {
  const target = $('Staged Create').all()[i].json.data.stagedUploadsCreate.stagedTargets[0];
  const headers = {};
  for (const p of (target.parameters || [])) { headers[p.name] = p.value; }
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  await this.helpers.httpRequest({ method: 'PUT', url: target.url, body: buffer, headers: headers });
  results.push({ json: { resourceUrl: target.resourceUrl, alt: $('Split Photos').all()[i].json.baseName } });
}
return results;

const items = $input.all();
const uploadedFiles = [];
for (const it of items) {
  const fc = it.json.data && it.json.data.fileCreate;
  if (fc && fc.files) { for (const f of fc.files) { uploadedFiles.push({ id: f.id, alt: f.alt }); } }
}
return [{ json: { uploadedFiles } }];
